CREATE TABLE DEPOSIT (    ACTNO  VARCHAR2(5),    CNAME  VARCHAR2(15),    BNAME  VARCHAR2(15),    AMOUNT NUMBER(9,2),    ADATE  DATE); CREATE TABLE BRANCH (    BNAME VARCHAR2(15),    CITY  VARCHAR2(15)); CREATE TABLE CUSTOMERS (    CNAME VARCHAR2(15),    CITY  VARCHAR2(15)); CREATE TABLE BORROW (    LOANNO VARCHAR2(5),    CNAME  VARCHAR2(15),    BNAME  VARCHAR2(15),    AMOUNT NUMBER(9,2)); -- ─── INSERT DATA ───────────────────────────────────────────── -- DEPOSITINSERT INTO DEPOSIT VALUES ('100', 'ANIL',    'VRCE',        1000.00, TO_DATE('01-MAR-95','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('101', 'SUNIL',   'AJNI',        5000.00, TO_DATE('04-JAN-96','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('102', 'MEHUL',   'KAROLBAGH',   3500.00, TO_DATE('17-NOV-95','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('104', 'MADHURI', 'CHANDI',      1200.00, TO_DATE('17-DEC-95','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('105', 'PRMOD',   'M G ROAD',    3000.00, TO_DATE('27-MAR-96','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('106', 'SANDIP',  'ANDHERI',     2000.00, TO_DATE('31-MAR-96','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('107', 'SHIVANI', 'VIRAR',       1000.00, TO_DATE('05-SEP-95','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('108', 'KRANTI',  'NEHRU PLACE', 5000.00, TO_DATE('02-JUL-95','DD-MON-YY'));INSERT INTO DEPOSIT VALUES ('109', 'MINU',    'POWAI',       7000.00, TO_DATE('10-AUG-95','DD-MON-YY')); -- BRANCHINSERT INTO BRANCH VALUES ('VRCE',        'NAGPUR');INSERT INTO BRANCH VALUES ('AJNI',        'NAGPUR');INSERT INTO BRANCH VALUES ('KAROLBAGH',   'DELHI');INSERT INTO BRANCH VALUES ('CHANDI',      'DELHI');INSERT INTO BRANCH VALUES ('DHARAMPETH',  'NAGPUR');INSERT INTO BRANCH VALUES ('M G ROAD',    'BANGLORE');INSERT INTO BRANCH VALUES ('ANDHERI',     'BOMBAY');INSERT INTO BRANCH VALUES ('VIRAR',       'BOMBAY');INSERT INTO BRANCH VALUES ('NEHRU PLACE', 'DELHI');INSERT INTO BRANCH VALUES ('POWAI',       'BOMBAY'); -- CUSTOMERSINSE